import{_ as e,W as c,X as d,Y as a}from"./framework-9a5142fa.js";const r={},n=a(`<p>[toc]</p><p>screen 创建窗口</p><p>ctrl + a +d 切出当前窗口</p><p>ctrl + a + k 杀死当前窗口</p><p>screen -ls</p><p>screen -r windowId</p><h2 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">apt</span> <span class="token function">install</span> <span class="token function">screen</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="机制" tabindex="-1"><a class="header-anchor" href="#机制" aria-hidden="true">#</a> 机制</h2><ul><li>在终端中输入<code>screen</code>创建多个screen命令窗口。</li><li>在screen命令窗口中可以创建多个会话窗口。</li></ul><h2 id="操作" tabindex="-1"><a class="header-anchor" href="#操作" aria-hidden="true">#</a> 操作</h2><h2 id="screen外和screen内的命令关系" tabindex="-1"><a class="header-anchor" href="#screen外和screen内的命令关系" aria-hidden="true">#</a> screen外和screen内的命令关系</h2><ul><li>在screen外（就是普通的终端中）：只可以使用以<code>screen</code>开头的命令</li><li>进入screen之后才能使用相关命令：以<code>screen</code>开头的命令 和 <code>^a</code>（Ctrl + a）系列 都可以使用</li></ul><p>PS：在screen外大<code>screen</code>进入screen窗口内</p><h3 id="screen内的命令" tabindex="-1"><a class="header-anchor" href="#screen内的命令" aria-hidden="true">#</a> screen内的命令</h3><p><code>^</code>表示同时按住<code>Ctrl</code><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406231915949.png" alt="在这里插入图片描述"></p><h4 id="创建" tabindex="-1"><a class="header-anchor" href="#创建" aria-hidden="true">#</a> 创建</h4><ul><li><code>screen</code>进入enter后自动创建一个会话窗口<code>0</code></li><li><code>^a → c</code>：创建一个会话窗口，数字增加1</li></ul><h4 id="显示" tabindex="-1"><a class="header-anchor" href="#显示" aria-hidden="true">#</a> 显示</h4><ul><li><p>当前screen窗口列表：<code>screen -ls</code></p><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406231915383.png" alt="在这里插入图片描述"></p><p>这个<code>9982</code>就是yourScreenId</p></li><li><p>当前会话窗口列表：<code>^a → *</code></p></li></ul><h4 id="切换" tabindex="-1"><a class="header-anchor" href="#切换" aria-hidden="true">#</a> 切换</h4><ul><li>后台运行screen窗口：<code>^a → d</code>或<code>screen -d yourScreenId</code></li><li>回到screen窗口：<code>screen -r yourScreenId</code></li></ul><p>【当出现Attached时，不让你回到screen窗口，怎么办？】 让它断开链接就能回去了：<code>screen -d yourScreenId</code>，然后<code>screen -r yourScreenId</code></p><h4 id="帮助" tabindex="-1"><a class="header-anchor" href="#帮助" aria-hidden="true">#</a> 帮助</h4><p><code>^a → ?</code></p><h4 id="退出" tabindex="-1"><a class="header-anchor" href="#退出" aria-hidden="true">#</a> 退出</h4><ul><li>退出当前： <code>exit</code> 或<code>^a → k</code>或<code>^a → K</code> 或<code>screen -ls</code>, <code>kill yourScreenId</code></li><li>退出全部：<code>^a → \\</code></li></ul>`,27),s=[n];function i(o,l){return c(),d("div",null,s)}const t=e(r,[["render",i],["__file","screen.html.vue"]]);export{t as default};
